        jsonify(
            {
                "accepted": True,
                "telemetry": telemetry,
                "report": report_record,
            }
        ),
        202,
    )


@app.get("/reports/summary")
def summary():
    #from summary_sdk import render_summary

    by_source = Counter(event["source"] for event in stored_events)
    #return jsonify(render_summary(len(stored_events), dict(by_source))), 200
    return jsonify({"total": len(stored_events), "sources": dict(by_source)}), 200


if __name__ == "__main__":
